import numpy as np
import cv2

# Image Negative
def image_negative(img, L=256):
    return L - 1 - img

# Log Transformation
def log_transform(img, c=None):
    if c is None:
        c = 255 / np.log(1 + 255)
    return c * np.log(1 + img.astype(float))

# Power-Law (Gamma) Transformation
def power_law(img, gamma, c=1.0):
    return c * np.power(img.astype(float), gamma)

# Contrast Stretching
def contrast_stretch(img, r1, s1, r2, s2):
    output = img.copy().astype(float)
    # First region
    mask1 = img <= r1
    output[mask1] = (s1 / r1) * img[mask1]
    # Second region
    mask2 = (img > r1) & (img <= r2)
    output[mask2] = s1 + ((s2 - s1) / (r2 - r1)) * (img[mask2] - r1)
    # Third region
    mask3 = img > r2
    output[mask3] = s2 + ((255 - s2) / (255 - r2)) * (img[mask3] - r2)
    return np.clip(output, 0, 255).astype(np.uint8)

# Bit-Plane Slicing
def bit_plane_slicing(img):
    planes = []
    for i in range(8):
        plane = (img >> i) & 1
        planes.append(plane * 255)
    return planes

