import java.awt.image.BufferedImage;

public class PointProcessing {

    // Image Negative
    public static BufferedImage negative(BufferedImage img) {
        int width = img.getWidth();
        int height = img.getHeight();
        BufferedImage result = new BufferedImage(width, height, BufferedImage.TYPE_BYTE_GRAY);

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int pixel = img.getRaster().getSample(x, y, 0);
                int newPixel = 255 - pixel;
                result.getRaster().setSample(x, y, 0, newPixel);
            }
        }
        return result;
    }

    // Power-Law Transformation
    public static BufferedImage powerLaw(BufferedImage img, double gamma) {
        int width = img.getWidth();
        int height = img.getHeight();
        BufferedImage result = new BufferedImage(width, height, BufferedImage.TYPE_BYTE_GRAY);

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                double pixel = img.getRaster().getSample(x, y, 0);
                int newPixel = (int) Math.pow(pixel / 255.0, gamma) * 255;
                result.getRaster().setSample(x, y, 0, newPixel);
            }
        }
        return result;
    }

    // Histogram Equalization
    public static BufferedImage histogramEqualization(BufferedImage img) {
        int width = img.getWidth();
        int height = img.getHeight();
        int[] histogram = new int[256];

        // Compute histogram
        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int pixel = img.getRaster().getSample(x, y, 0);
                histogram[pixel]++;
            }
        }

        // Compute CDF
        int[] cdf = new int[256];
        cdf[0] = histogram[0];
        for (int i = 1; i < 256; i++) {
            cdf[i] = cdf[i-1] + histogram[i];
        }

        // Find minimum
        int cdfMin = 0;
        for (int i = 0; i < 256; i++) {
            if (cdf[i] > 0) {
                cdfMin = cdf[i];
                break;
            }
        }

        // Apply transformation
        BufferedImage result = new BufferedImage(width, height, BufferedImage.TYPE_BYTE_GRAY);
        int totalPixels = width * height;

        for (int y = 0; y < height; y++) {
            for (int x = 0; x < width; x++) {
                int pixel = img.getRaster().getSample(x, y, 0);
                int newPixel = (int) (((cdf[pixel] - cdfMin) * 255.0) / (totalPixels - cdfMin));
                result.getRaster().setSample(x, y, 0, newPixel);
            }
        }
        return result;
    }
}
